The reference solution of that problem in Javascript is 
function solve(s, k) {
    let result = [];
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (c === '#') {
            result = result.concat(result);
        } else if (c === '%') {
            result = result.slice().reverse();
        } else if (c === '*') {
            if (result.length > 0) {
                result.pop();
            }
        } else {
            result.push(c);
        }
    }
    if (k < 0 || k >= result.length) {
        return '.';
    } else {
        return result[k];
    }
}

